1	import { Injectable, Logger, UnauthorizedException } from '@nestjs/common';
2	import { TransactionHost } from '@nestjs-cls/transactional';
3	import { OAuth2Client } from 'google-auth-library';
4	import appleSignin from 'apple-signin-auth';
5	import axios from 'axios';
6	import { v4 as uuid } from 'uuid';
7	
8	import { FileEntity, FileStatus } from '@/db';
9	import { MimeType } from '@/common';
10	import { TransactionalAdapterTypeOrm } from '@/modules/global';
11	import { StorageService } from '@/modules/file/services/storage.service';
12	import { env } from '@/env';
13	
14	const GOOGLE_AVATAR_FOLDER = 'files';
15	
16	@Injectable()
17	export class SocialAuthService {
18	  private readonly logger = new Logger(SocialAuthService.name);
19	  private readonly googleClient = new OAuth2Client(env.GOOGLE_CLIENT_ID);
20	
21	  constructor(
22	    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
23	    private readonly storageService: StorageService,
24	  ) {}
25	
26	  async verifyGoogleToken(idToken: string): Promise<{
27	    email: string;
28	    firstName: string;
29	    lastName: string;
30	    picture: string | null;
31	  }> {
32	    let ticket;
33	    try {
34	      ticket = await this.googleClient.verifyIdToken({
35	        idToken,
36	        audience: env.GOOGLE_CLIENT_ID,
37	      });
38	    } catch (err) {
39	      this.logger.error(`[Google] Token verification failed: ${err?.message}`);
40	      throw new UnauthorizedException('Invalid Google token');
41	    }
42	
43	    const payload = ticket.getPayload();
44	    if (!payload?.email) {
45	      throw new UnauthorizedException('Google token missing email');
46	    }
47	
48	    return {
49	      email: payload.email,
50	      firstName: payload.given_name ?? '',
51	      lastName: payload.family_name ?? '',
52	      picture: payload.picture ?? null,
53	    };
54	  }
55	
56	  async verifyAppleToken(
57	    identityToken: string,
58	  ): Promise<{ appleUserId: string; email: string | null }> {
59	    let payload;
60	    try {
61	      payload = await appleSignin.verifyIdToken(identityToken, {
62	        audience: env.APPLE_CLIENT_ID,
63	        ignoreExpiration: false,
64	      });
65	    } catch {
66	      throw new UnauthorizedException('Invalid Apple token');
67	    }
68	
69	    return {
70	      appleUserId: payload.sub,
71	      email: (payload.email as string | undefined) ?? null,
72	    };
73	  }
74	
75	  async uploadAvatarFromUrl(pictureUrl: string): Promise<FileEntity | null> {
76	    // Request larger image by removing Google's size suffix (e.g. =s96-c)
77	    const url = pictureUrl.replace(/=s\d+-c$/, '=s400-c');
78	
79	    this.logger.log(`[Google] Downloading avatar from: ${url}`);
80	
81	    try {
82	      const response = await axios.get<ArrayBuffer>(url, {
83	        responseType: 'arraybuffer',
84	        timeout: 10000,
85	      });
86	
87	      const contentType = (response.headers['content-type'] as string) ?? '';
88	      this.logger.log(`[Google] Avatar content-type: ${contentType}`);
89	
90	      const mime = this.resolveImageMime(contentType);
91	
92	      if (!mime) {
93	        this.logger.warn(`[Google] Unsupported avatar mime type: ${contentType}`);
94	        return null;
95	      }
96	
97	      const fileId = uuid();
98	      const path = `/${GOOGLE_AVATAR_FOLDER}/${fileId}`;
99	
100	      await this.storageService.upload(path, Buffer.from(response.data));
101	      this.logger.log(`[Google] Avatar uploaded to S3: ${path}`);
102	
103	      const fileRepo = this.txHost.tx.getRepository(FileEntity);
104	      const file = await fileRepo.save({
105	        id: fileId,
106	        path,
107	        mime,
108	        name: `avatar-${fileId}`,
109	        status: FileStatus.UPLOADED,
110	        uploadedAt: new Date(),
111	      });
112	
113	      this.logger.log(`[Google] Avatar saved as FileEntity: ${file.id}`);
114	      return file;
115	    } catch (err) {
116	      this.logger.warn(`[Google] Failed to upload avatar: ${err?.message}`);
117	      return null;
118	    }
119	  }
120	
121	  private resolveImageMime(contentType: string): MimeType | null {
122	    if (contentType.includes('image/jpeg') || contentType.includes('image/jpg')) {
123	      return MimeType.ImageJpeg;
124	    }
125	    if (contentType.includes('image/png')) {
126	      return MimeType.ImagePng;
127	    }
128	    if (contentType.includes('image/webp')) {
129	      // Store webp as jpeg mime — S3 accepts the raw bytes regardless
130	      return MimeType.ImageJpeg;
131	    }
132	    return null;
133	  }
134	}
