80	  async signUp(dto: {
81	    password: string;
82	    firstName: string;
83	    lastName: string;
84	    patronymic?: string | null;
85	    phoneOtpId: string;
86	    emailOtpId: string;
87	    role: UserRole;
88	  }) {
89	    const {
90	      password,
91	      firstName,
92	      lastName,
93	      patronymic,
94	      phoneOtpId,
95	      emailOtpId,
96	    } = dto;
97	
98	    this.logger.log(
99	      `[signUp] Start: emailOtpId=${emailOtpId}, phoneOtpId=${phoneOtpId}, role=${dto.role}`,
100	    );
101	
102	    const emailOtp = await this.otpService.findApproved(
103	      emailOtpId,
104	      OtpType.SignUp,
105	      MediaType.Email,
106	    );
107	
108	    this.logger.log(`[signUp] Email OTP approved for: ${emailOtp.sentTo}`);
109	
110	    const phoneOtp = await this.otpService.findApproved(
111	      phoneOtpId,
112	      OtpType.SignUp,
113	      MediaType.Phone,
114	    );
115	
116	    this.logger.log(`[signUp] Phone OTP approved for: ${phoneOtp.sentTo}`);
117	
118	    const emailExists = await this.emailExists(emailOtp.sentTo);
119	
120	    if (emailExists) {
121	      this.logger.warn(
122	        `[signUp] Rejected: email already exists — ${emailOtp.sentTo}`,
123	      );
124	      throw new BadRequestException('User with this email already exists');
125	    }
126	
127	    const phoneExists = await this.phoneExists(phoneOtp.sentTo);
128	
129	    if (phoneExists) {
130	      this.logger.warn(
131	        `[signUp] Rejected: phone already exists — ${phoneOtp.sentTo}`,
132	      );
133	      throw new BadRequestException('User with this phone already exists');
134	    }
135	
136	    try {
137	      if (!env.AWS_COGNITO_SKIP) {
138	        this.logger.log(
139	          `[signUp] Creating Cognito user for: ${emailOtp.sentTo}`,
140	        );
141	        await this.cognitoService.signUp({
142	          email: emailOtp.sentTo,
143	          firstName,
144	          lastName,
145	          patronymic,
146	          password,
147	        });
148	        this.logger.log(
149	          `[signUp] Cognito user created successfully for: ${emailOtp.sentTo}`,
150	        );
151	      }
152	
153	      this.logger.log(`[signUp] Creating DB user for: ${emailOtp.sentTo}`);
154	      await this.userService.create({
155	        email: emailOtp.sentTo,
156	        phone: phoneOtp.sentTo,
157	        firstName,
158	        lastName,
159	        patronymic,
160	        roles: [dto.role],
161	        status: UserStatus.Active,
162	      });
163	      this.logger.log(
164	        `[signUp] DB user created successfully for: ${emailOtp.sentTo}`,
165	      );
166	
167	      await this.otpService.removeOtp([emailOtpId, phoneOtpId]);
168	
169	      this.logger.log(
170	        `[signUp] Signing in after registration for: ${emailOtp.sentTo}`,
171	      );
172	      return this.signIn({
173	        email: emailOtp.sentTo,
174	        password,
175	      });
176	    } catch (error) {
177	      const errorName =
178	        error?.name ?? error?.constructor?.name ?? 'UnknownError';
179	      const errorMessage = error?.message ?? String(error);
180	      const errorCode =
181	        error?.$metadata?.httpStatusCode ?? error?.code ?? 'N/A';
182	
183	      this.logger.error(
184	        `[signUp] Failed for email=${emailOtp?.sentTo}, phone=${phoneOtp?.sentTo}: [${errorName}] (HTTP ${errorCode}) ${errorMessage}`,
185	        error?.stack,
186	      );
187	
188	      // todo: handle invalid passwords separately
189	      if (error instanceof UserNotConfirmedException) {
190	        throw new BadRequestException('Invalid password');
191	      } else {
192	        throw new InternalServerErrorException();
193	      }
194	    }
195	  }
