197	  async signIn(dto: { email: string; password: string }) {
198	    const result = await this.cognitoService.signIn(dto.email, dto.password);
199	
200	    const user = await this.txHost.tx.getRepository(UserEntity).findOne({
201	      where: { email: dto.email },
202	    });
203	
204	    if (!user) {
205	      await this.cognitoService.deleteUser(dto.email);
206	      throw new UnauthorizedException('Email is not registered');
207	    }
208	
209	    // Check if we got a challenge (temporary password case)
210	    if (result.ChallengeName === 'NEW_PASSWORD_REQUIRED') {
211	      return {
212	        status: 'CHALLENGE',
213	        challengeName: result.ChallengeName,
214	        session: result.Session,
215	        challengeParameters: result.ChallengeParameters,
216	        message: 'Temporary password detected. New password required.',
217	      };
218	    }
219	
220	    if (result.AuthenticationResult?.AccessToken) {
221	      return {
222	        status: 'SUCCESS',
223	        payload: {
224	          accessToken: isDevelopment()
225	            ? dto.email
226	            : result.AuthenticationResult.AccessToken,
227	          refreshToken: result.AuthenticationResult.RefreshToken,
228	          idToken: result.AuthenticationResult.IdToken,
229	        },
230	      };
231	    }
232	
233	    return {
234	      status: 'FAILED',
235	      message: 'Authentication failed',
236	    };
237	  }
