482	  async forgotPassword(dto: {
483	    email?: string;
484	    phone?: string;
485	    mediaType: MediaType;
486	  }) {
487	    const userRepository = this.txHost.tx.getRepository(UserEntity);
488	
489	    const isEmail = dto.mediaType === MediaType.Email;
490	    const source = isEmail ? dto.email! : dto.phone!;
491	
492	    const user = await userRepository.findOne({
493	      where: isEmail ? { email: source } : { phone: source },
494	    });
495	
496	    if (!user) {
497	      throw new NotFoundException('User not found');
498	    }
499	
500	    const otpResponse = await this.otpService.sendOtp([
501	      {
502	        source,
503	        type: OtpType.ForgotPassword,
504	        mediaType: dto.mediaType,
505	      },
506	    ]);
507	
508	    return {
509	      status: 'SUCCESS',
510	      message: isEmail
511	        ? 'Password reset code sent to your email'
512	        : 'Password reset code sent to your phone',
513	      ...(otpResponse.otp ? { otp: otpResponse.otp } : {}),
514	    };
515	  }
516	
517	  async confirmForgotPassword(dto: { otpId: string; newPassword: string }) {
518	    try {
519	      const otpRepository = this.txHost.tx.getRepository(OtpEntity);
520	
521	      const otp = await otpRepository.findOne({
522	        where: {
523	          id: dto.otpId,
524	          approved: true,
525	          type: OtpType.ForgotPassword,
526	        },
527	      });
528	
529	      if (!otp) {
530	        throw new UnauthorizedException('Invalid OTP');
531	      }
532	
533	      if (!env.AWS_COGNITO_SKIP) {
534	        await this.cognitoService.changePassword(otp.sentTo, dto.newPassword);
535	      }
536	
537	      return {
538	        status: 'SUCCESS',
539	        message: 'Password reset successfully',
540	      };
541	    } catch (error) {
542	      return {
543	        status: 'FAILED',
544	        message: error.message,
545	      };
546	    }
547	  }
548	}
