33	@Injectable()
34	export class CognitoService {
35	  private readonly logger = new Logger(CognitoService.name);
36	  private readonly cognitoClient: CognitoIdentityProviderClient;
37	  private readonly userPoolId: string;
38	  private readonly clientId: string;
