285	  private deriveSocialPassword(email: string): string {
286	    const hash = createHmac('SHA256', env.JWT_SECRET)
287	      .update(email + ':social')
288	      .digest('hex');
289	    // Prefix satisfies Cognito policy: uppercase, lowercase, digit, special char
290	    return `Aa1!${hash}`;
291	  }
