293	  async signInSocialUser(dto: {
294	    email: string;
295	    firstName: string;
296	    lastName: string;
297	  }): Promise<{ accessToken: string; refreshToken: string; idToken: string }> {
298	    if (env.AWS_COGNITO_SKIP) {
299	      return {
300	        accessToken: dto.email,
301	        refreshToken: `${dto.email}:refresh`,
302	        idToken: `${dto.email}:id`,
303	      };
304	    }
305	
306	    const password = this.deriveSocialPassword(dto.email);
307	    const fullName = [dto.firstName, dto.lastName].filter(Boolean).join(' ');
308	
309	    let userExists = false;
310	    try {
311	      await this.cognitoClient.send(
312	        new AdminGetUserCommand({
313	          UserPoolId: this.userPoolId,
314	          Username: dto.email,
315	        }),
316	      );
317	      userExists = true;
318	      this.logger.log(`[Social] User exists in Cognito: ${dto.email}`);
319	    } catch (err) {
320	      if (err?.name !== 'UserNotFoundException') {
321	        this.logger.error(
322	          `[Social] Error checking user: ${err?.name} — ${err?.message}`,
323	          err?.stack,
324	        );
325	        throw err;
326	      }
327	    }
328	
329	    try {
330	      if (!userExists) {
331	        this.logger.log(`[Social] Creating Cognito user: ${dto.email}`);
332	        await this.cognitoClient.send(
333	          new AdminCreateUserCommand({
334	            UserPoolId: this.userPoolId,
335	            Username: dto.email,
336	            MessageAction: 'SUPPRESS',
337	            UserAttributes: [
338	              { Name: 'email', Value: dto.email },
339	              { Name: 'email_verified', Value: 'true' },
340	              { Name: 'name', Value: fullName },
341	            ],
342	          }),
343	        );
344	        this.logger.log(`[Social] User created: ${dto.email}`);
345	      }
346	
347	      // Always set password — idempotent, handles partial failures
348	      await this.changePassword(dto.email, password);
349	      this.logger.log(`[Social] Password set for: ${dto.email}`);
350	    } catch (err) {
351	      this.logger.error(
352	        `[Social] Failed to create/configure user ${dto.email}: ${err?.name} — ${err?.message}`,
353	        err?.stack,
354	      );
355	      throw err;
356	    }
357	
358	    try {
359	      this.logger.log(`[Social] Signing in: ${dto.email}`);
360	      const result = await this.cognitoClient.send(
361	        new InitiateAuthCommand({
362	          ClientId: this.clientId,
363	          AuthFlow: 'USER_PASSWORD_AUTH',
364	          AuthParameters: {
365	            USERNAME: dto.email,
366	            PASSWORD: password,
367	            SECRET_HASH: this.generateSecretHash(dto.email),
368	          },
369	        }),
370	      );
371	
372	      if (!result.AuthenticationResult?.AccessToken) {
373	        throw new UnauthorizedException('Social Cognito sign-in failed');
374	      }
375	
376	      this.logger.log(`[Social] Sign-in successful: ${dto.email}`);
377	      return {
378	        accessToken: result.AuthenticationResult.AccessToken,
379	        refreshToken: result.AuthenticationResult.RefreshToken!,
380	        idToken: result.AuthenticationResult.IdToken!,
381	      };
382	    } catch (err) {
383	      this.logger.error(
384	        `[Social] Sign-in failed for ${dto.email}: ${err?.name} — ${err?.message}`,
385	        err?.stack,
386	      );
387	      throw err;
388	    }
389	  }
