442	  private async getUserAttributesFromRaw(
443	    userAttributes: AttributeType[],
444	  ): Promise<{
445	    email: string;
446	    firstName: string;
447	    lastName: string;
448	    phone: string;
449	    picture: string | null;
450	  }> {
451	    const res = userAttributes.reduce((acc, attribute) => {
452	      acc[attribute.Name!] = attribute.Value;
453	      return acc;
454	    }, {}) as {
455	      email: string;
456	      name: string;
457	      given_name?: string;
458	      family_name?: string;
459	      phone_number: string;
460	      picture?: string;
461	    };
462	
463	    const nameParts = (res.name || '').trim().split(/\s+/);
464	    const firstName = res.given_name || nameParts[0] || '';
465	    const lastName =
466	      res.family_name ||
467	      (nameParts.length > 1 ? nameParts[nameParts.length - 1] : '');
468	
469	    return {
470	      email: res.email,
471	      firstName,
472	      lastName,
473	      phone: res.phone_number,
474	      picture: res.picture ?? null,
475	    };
476	  }
