487	  async getAccessTokenOwnerEmail(accessToken: string) {
488	    const verifier = CognitoJwtVerifier.create({
489	      userPoolId: this.userPoolId,
490	      tokenUse: 'access',
491	      clientId: this.clientId,
492	    });
493	
494	    const payload = await verifier.verify(accessToken, {
495	      clientId: this.clientId,
496	      tokenUse: 'access',
497	      includeRawJwtInErrors: true,
498	    });
499	
500	    const user = await this.cognitoClient.send(
501	      new AdminGetUserCommand({
502	        UserPoolId: this.userPoolId,
503	        Username: payload.username,
504	      }),
505	    );
506	
507	    if (!user || !user.UserAttributes) {
508	      throw new UnauthorizedException('Email is not registered');
509	    }
510	
511	    const attributes = user.UserAttributes.reduce((acc, attribute) => {
512	      if (attribute.Name) {
513	        acc[attribute.Name] = attribute.Value;
514	      }
515	      return acc;
516	    }, {}) as Record<string, string>;
517	
518	    const email = attributes.email ? attributes.email : null;
519	
520	    if (!email) {
521	      throw new UnauthorizedException(`User doesn't have email`);
522	    }
523	
524	    return email;
525	  }
