527	  async getUserAttributesByEmail(email: string) {
528	    const result = await this.getUserByEmail(email);
529	
530	    if (!result.UserAttributes) {
531	      return null;
532	    }
533	
534	    return this.getUserAttributesFromRaw(result.UserAttributes);
535	  }
536	
537	  private decodeJwtToken(token: string): Record<string, string> | null {
538	    try {
539	      const base64Url = token.split('.')[1];
540	      const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
541	      const jsonPayload = decodeURIComponent(
542	        Buffer.from(base64, 'base64')
543	          .toString()
544	          .split('')
545	          .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
546	          .join(''),
547	      );
548	      return JSON.parse(jsonPayload) as Record<string, string>;
549	    } catch {
550	      return null;
551	    }
552	  }
553	}
