2	  CanActivate,
3	  ExecutionContext,
4	  Injectable,
5	  UnauthorizedException,
6	} from '@nestjs/common';
7	import { Reflector } from '@nestjs/core';
8	import { JwtService } from '@nestjs/jwt';
9	import { TransactionHost } from '@nestjs-cls/transactional';
10	
11	import {
12	  AdminEntity,
13	  AuthenticatorEntity,
14	  Permission,
15	  UserEntity,
16	  UserRole,
17	  UserStatus,
18	} from '@/db';
19	
20	import { ContextService, TransactionalAdapterTypeOrm } from '@/modules/global';
21	import { UN_PROTECT_KEY } from '../decorators';
22	import { CognitoService } from '../services';
23	import { AuthenticatedPersonFastifyRequest } from '../types';
24	import { EMAIL_AUTH_ENABLED, env } from '@/env';
25	
26	function extractBearerToken(header: string | undefined) {
27	  const [type, token] = header ? header.split(' ') : [];
28	
29	  return type === 'Bearer' ? token : null;
30	}
31	
32	@Injectable()
33	export class AuthGuard implements CanActivate {
34	  constructor(
35	    private readonly reflector: Reflector,
36	    private readonly txHost: TransactionHost<TransactionalAdapterTypeOrm>,
37	    private readonly cognitoService: CognitoService,
38	    private readonly contextService: ContextService,
39	    private readonly jwtService: JwtService,
40	  ) {}
41	
42	  public async canActivate(context: ExecutionContext): Promise<boolean> {
43	    const isUnProtectedDecoratorSpecified =
44	      this.reflector.getAllAndOverride<boolean>(UN_PROTECT_KEY, [
45	        context.getHandler(),
46	        context.getClass(),
47	      ]);
48	
49	    if (isUnProtectedDecoratorSpecified) {
50	      return true;
51	    }
52	
53	    const type = context.getType();
54	
55	    const requiredUserRoles = this.reflector.getAllAndOverride<UserRole[]>(
56	      'roles',
57	      [context.getHandler(), context.getClass()],
58	    );
59	
60	    const requiredPermission = this.reflector.getAllAndOverride<Permission>(
61	      'permission',
62	      [context.getHandler(), context.getClass()],
63	    );
64	
65	    if (type === 'http') {
66	      return this.handleHttp(context, requiredUserRoles, requiredPermission);
67	    }
68	
69	    return false;
70	  }
71	
72	  private async handleHttp(
73	    context: ExecutionContext,
74	    userRoles: UserRole[],
75	    permission: Permission,
76	  ) {
77	    const request = context
78	      .switchToHttp()
79	      .getRequest<AuthenticatedPersonFastifyRequest>();
80	    const jwt = extractBearerToken(request.headers.authorization);
81	
82	    if (!jwt) {
83	      throw new UnauthorizedException();
84	    }
85	
86	    let email: string;
87	
88	    if (EMAIL_AUTH_ENABLED) {
89	      email = await this.resolveEmailDev(jwt);
90	    } else {
91	      email = await this.resolveEmail(jwt);
92	    }
93	
94	    const userRepository = this.txHost.tx.getRepository(UserEntity);
95	
96	    const user = await userRepository.findOne({
97	      where: {
98	        email,
99	        status: UserStatus.Active,
100	      },
101	    });
102	
103	    if (!user) {
104	      throw new UnauthorizedException();
105	    }
106	
107	    this.contextService.context.user = user;
108	    this.contextService.context.role = user.selectedRole;
109	
110	    if (userRoles?.length && !userRoles.includes(user.selectedRole)) {
111	      throw new UnauthorizedException();
112	    }
113	
114	    if (user.selectedRole === UserRole.Authenticator) {
115	      const authenticatorRepository =
116	        this.txHost.tx.getRepository(AuthenticatorEntity);
117	      const authenticator = await authenticatorRepository.findOne({
118	        where: {
119	          user: { id: user.id },
120	        },
121	      });
122	
123	      if (!authenticator) {
124	        throw new UnauthorizedException();
125	      }
126	
127	      this.contextService.context.authenticatorId = authenticator.id;
128	    }
129	
130	    if ([UserRole.Admin, UserRole.SuperAdmin].includes(user.selectedRole)) {
131	      const adminRepository = this.txHost.tx.getRepository(AdminEntity);
132	      const admin = await adminRepository.findOne({
133	        where: {
134	          user: { id: user.id },
135	        },
136	        relations: ['adminRoles'],
137	      });
138	
139	      if (!admin) {
140	        throw new UnauthorizedException();
141	      }
142	
143	      if (user.selectedRole === UserRole.Admin) {
144	        const adminPermissions = admin.adminRoles.flatMap(
145	          (role) => role.permissions,
146	        );
147	
148	        this.contextService.context.permissions = adminPermissions;
149	      }
150	
151	      if (user.selectedRole === UserRole.SuperAdmin) {
152	        this.contextService.context.permissions = Object.values(Permission);
153	      }
154	
155	      this.contextService.context.admin = admin;
156	    }
157	
158	    if (
159	      permission &&
160	      !this.contextService.context.permissions.includes(permission)
161	    ) {
162	      throw new UnauthorizedException();
163	    }
164	
165	    request.token = jwt;
166	    request.user = user;
167	
168	    return true;
169	  }
170	
171	  private async resolveEmail(jwt: string): Promise<string> {
172	    try {
173	      return await this.cognitoService.getAccessTokenOwnerEmail(jwt);
174	    } catch {
175	      throw new UnauthorizedException();
176	    }
177	  }
178	
179	  private async resolveEmailDev(jwt: string): Promise<string> {
180	    // 1. Our own JWT (social auth in dev)
181	    try {
182	      const payload = this.jwtService.verify<{ sub: string }>(jwt, {
183	        secret: env.JWT_SECRET,
184	      });
185	      if (payload?.sub) return payload.sub;
186	    } catch {
187	      // not our JWT
188	    }
189	
190	    // 2. Cognito token (social auth via Cognito in dev)
191	    try {
192	      return await this.cognitoService.getAccessTokenOwnerEmail(jwt);
193	    } catch {
194	      // not a Cognito token
195	    }
196	
197	    // 3. Raw email (standard dev login)
198	    return jwt;
199	  }
200	}
