33	  private async handleHttp(context: ExecutionContext) {
34	    const request = context
35	      .switchToHttp()
36	      .getRequest<AuthenticatedPersonFastifyRequest>();
37	    const jwt = extractBearerToken(request.headers.authorization);
38	
39	    if (!jwt) return;
40	
41	    let email: string;
42	
43	    try {
44	      if (EMAIL_AUTH_ENABLED) {
45	        email = jwt;
46	      } else {
47	        email = await this.cognitoService.getAccessTokenOwnerEmail(jwt);
48	      }
49	    } catch {
50	      return;
51	    }
52	
53	    const userRepository = this.txHost.tx.getRepository(UserEntity);
54	    const user = await userRepository.findOne({
55	      where: { email, status: UserStatus.Active },
56	    });
57	
58	    if (!user) return;
59	
60	    this.contextService.context.user = user;
61	    this.contextService.context.role = user.selectedRole;
62	
63	    request.token = jwt;
64	    request.user = user;
65	  }
66	}
