2	
3	import multipart from '@fastify/multipart';
4	import { Logger, ValidationPipe } from '@nestjs/common';
5	import { NestFactory } from '@nestjs/core';
6	import {
7	  FastifyAdapter,
8	  NestFastifyApplication,
9	} from '@nestjs/platform-fastify';
10	import { DocumentBuilder, SwaggerModule } from '@nestjs/swagger';
11	import * as process from 'node:process';
12	
13	import { LoggingInterceptor } from '@/common/interceptors';
14	import { configureRawBody } from '@/common/config/fastify-raw-body.config';
15	
16	import { env } from './env';
17	import { RootModule } from './root.module';
18	
19	process.on('unhandledRejection', (reason) => {
20	  Logger.error(`Unhandled Rejection reason: ${reason}`, (reason as any)?.stack);
21	});
22	
23	function setupSwagger(app: NestFastifyApplication) {
24	  const config = new DocumentBuilder()
25	    .setTitle('LuxFlow API')
26	    .setDescription('API documentation for LuxFlow')
27	    .setVersion('0.0.1')
28	    .addBearerAuth()
29	    .build();
30	  const documentFactory = () => SwaggerModule.createDocument(app, config);
31	
32	  SwaggerModule.setup(env.SWAGGER_ENDPOINT, app, documentFactory, {
33	    swaggerOptions: {
34	      persistAuthorization: true,
35	    },
36	  });
37	}
38	
39	function setupHttp(app: NestFastifyApplication) {
40	  app.useGlobalPipes(
41	    new ValidationPipe({
42	      whitelist: true,
43	      transform: true,
44	      transformOptions: { enableImplicitConversion: true },
45	    }),
46	  );
47	
48	  // Apply global interceptors for HTTP request logging
49	  app.useGlobalInterceptors(new LoggingInterceptor());
50	
51	  Logger.log('HTTP request logging enabled', 'API');
52	}
53	
54	function setupCors(app: NestFastifyApplication) {
55	  app.enableCors({
56	    origin: env.CORE_ORIGINS,
57	    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE'],
58	    credentials: true,
59	  });
60	}
61	
62	async function bootstrap() {
63	  const fastifyAdapter = new FastifyAdapter();
64	
65	  const app = await NestFactory.create<NestFastifyApplication>(
66	    RootModule,
67	    fastifyAdapter,
68	    {
69	      snapshot: true,
70	    },
71	  );
72	
73	  // eslint-disable-next-line @typescript-eslint/ban-ts-comment
74	  // @ts-expect-error
75	  await app.register(multipart, {
76	    attachFieldsToBody: 'keyValues',
77	    onFile: async (file) => {
78	      await file.toBuffer();
79	
80	      // exclude `fields` property from a result, because it leads to callstack exceed
81	      // eslint-disable-next-line @typescript-eslint/no-unused-vars
82	      const { fields, ...rest } = file;
83	      // @ts-expect-error is ok
84	      file.value = rest;
85	    },
86	    limits: {
87	      fileSize: 20_971_520,
88	    },
89	  });
90	
91	  // Configure raw body capture for webhook routes (required for signature verification)
92	  const fastifyInstance = app.getHttpAdapter().getInstance();
93	  configureRawBody(fastifyInstance);
94	
95	  setupHttp(app);
96	  setupCors(app);
97	  setupSwagger(app);
98	
99	  await app.listen(env.CORE_PORT, env.CORE_HOST);
100	}

1	import { Readable } from 'node:stream';
2	
3	import {
4	  DeleteObjectCommand,
5	  GetObjectCommand,
6	  GetObjectCommandInput,
7	  PutObjectCommand,
8	  S3Client,
9	} from '@aws-sdk/client-s3';
10	import {
11	  PresignedPostOptions,
12	  createPresignedPost,
13	} from '@aws-sdk/s3-presigned-post';
14	import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
15	import { Injectable } from '@nestjs/common';
16	import { ConfigService } from '@nestjs/config';
17	import { NodeJsRuntimeStreamingBlobPayloadInputTypes } from '@smithy/types';
18	
19	import { MimeType } from '@/common';
20	import { FileEntity } from '@/db';
21	
22	@Injectable()
23	export class StorageService {
24	  private readonly s3: S3Client;
25	  private readonly bucket: string;
26	
27	  constructor(private readonly configService: ConfigService) {
28	    this.s3 = new S3Client({
29	      region: this.configService.get('AWS_S3_REGION'),
30	      credentials: {
31	        accessKeyId: this.configService.get('AWS_ACCESS_KEY_ID')!,
32	        secretAccessKey: this.configService.get('AWS_SECRET_ACCESS_KEY')!,
33	      },
34	    });
35	    this.bucket = this.configService.get('AWS_S3_BUCKET')!;
36	  }
37	
38	  static getFileKey(path: string): string {
39	    return path[0] === '/' ? path.substring(1) : path;
40	  }
41	
42	  async upload(
43	    path: string,
44	    blob: NodeJsRuntimeStreamingBlobPayloadInputTypes,
45	  ) {
46	    await this.s3.send(
47	      new PutObjectCommand({
48	        Bucket: this.bucket,
49	        Key: StorageService.getFileKey(path),
50	        Body: blob,
51	      }),
52	    );
53	  }
54	
55	  async get(path: string) {
56	    const { Body } = await this.s3.send(
57	      new GetObjectCommand({
58	        Bucket: this.bucket,
59	        Key: StorageService.getFileKey(path),
60	      }),
61	    );
62	
63	    return Body as Readable;
64	  }
65	
66	  async getBuffer(path: string): Promise<Buffer> {
67	    const stream = await this.get(path);
68	    return this.streamToBuffer(stream);
69	  }
70	
71	  private async streamToBuffer(stream: Readable): Promise<Buffer> {
72	    const chunks: Buffer[] = [];
73	    return new Promise((resolve, reject) => {
74	      stream.on('data', (chunk) => chunks.push(chunk));
75	      stream.on('error', reject);
76	      stream.on('end', () => resolve(Buffer.concat(chunks)));
77	    });
78	  }
79	
80	  async signGetUrl(
81	    file: FileEntity,
82	    options?: Omit<GetObjectCommandInput, 'Key' | 'Bucket'>,
83	  ) {
84	    const fileName = file.name;
85	
86	    return getSignedUrl(
87	      this.s3,
88	      new GetObjectCommand({
89	        ...options,
90	        Bucket: this.bucket,
91	        Key: StorageService.getFileKey(file.path),
92	        ResponseContentDisposition: `attachment; filename="${fileName}"`,
93	      }),
94	      { expiresIn: 60 * 15 },
95	    );
96	  }
97	
98	  async signPostUrl(path: string, mime: MimeType) {
99	    const params: PresignedPostOptions = {
100	      Bucket: this.bucket,
101	      Key: StorageService.getFileKey(path),
102	      Conditions: [
103	        [
104	          'content-length-range',
105	          0,
106	          this.configService.get<number>('AWS_S3_UPLOAD_FILE_SIZE_LIMIT')!,
107	        ],
108	        ['eq', '$Content-Type', mime],
109	      ],
110	      Fields: {
111	        'Content-Type': mime,
112	      },
113	      Expires: 60 * 15,
114	    };
115	
116	    return createPresignedPost(this.s3, params);
117	  }
118	
119	  async delete(path: string) {
120	    await this.s3.send(
121	      new DeleteObjectCommand({
122	        Bucket: this.bucket,
123	        Key: StorageService.getFileKey(path),
124	      }),
125	    );
126	  }
127	}
