1	import { SetMetadata, UseGuards, applyDecorators } from '@nestjs/common';
2	import { ApiBearerAuth } from '@nestjs/swagger';
3	
4	import { Permission, UserRole } from '@/db';
5	
6	import { AuthGuard } from '../guards';
7	
8	export function Protected(roles?: UserRole[], permission?: Permission) {
9	  const guards: any[] = [AuthGuard];
10	
11	  const decorators = [UseGuards(...guards), ApiBearerAuth()];
12	
13	  if (roles) {
14	    decorators.push(SetMetadata('roles', roles));
15	  }
16	
17	  if (permission) {
18	    decorators.push(SetMetadata('permission', permission));
19	  }
20	
21	  return applyDecorators(...decorators);
22	}
